-- Issue #252: refine existing Hirado Seto representatives and add Hirado Port without reassigning user data.
update public.fishing_spots
set latitude = 33.362153,
    longitude = 129.574114,
    notes = array['国土地理院の地名代表点を基準にした田平港の概略代表点であり、港内の岸壁、入口、駐車位置、堤防先端、実釣位置、危険箇所を示しません。', '一般立入・釣り可否は未確認のため、現地表示と管理者の最新案内を確認してください。', '魚種・釣法は日付・地点・遊漁文脈を伴う直接根拠不足のため掲載していません。']::text[]
where id = 'tabira-port' and is_active = true;

update public.fishing_spots
set latitude = 33.363946,
    longitude = 129.569344,
    notes = array['国土地理院の地名代表点を基準にした平戸瀬戸周辺の広域district概略代表点です。田平港と平戸港を包含する水道文脈であり、港、橋、橋脚、灯台、堤防先端、磯入口、駐車位置、危険箇所、実釣位置を示しません。', '一般立入・釣り可否は未確認のため、現地表示と管理者の最新案内を確認してください。', '魚種・釣法は日付・地点・遊漁文脈を伴う直接根拠不足のため掲載していません。']::text[]
where id = 'hirado-seto' and is_active = true;

insert into public.fishing_spots (id,name,area_name,latitude,longitude,spot_type,shore_access,coordinate_precision,target_species,recommended_methods,notes,is_active) values
('hirado-port', '平戸港', '平戸', 33.37096, 129.553782, 'その他', '不明', 'approximate', array[]::text[], array[]::text[], array['国土地理院の地名代表点を基準にした港湾の概略代表点であり、入口、岸壁、堤防先端、駐車位置、実釣位置、危険箇所を示しません。', '一般立入・釣り可否は未確認のため、現地表示と管理者の最新案内を確認してください。', '魚種・釣法・設備・地形・SCORE情報は直接根拠不足のため掲載していません。']::text[], true)
on conflict (id) do nothing;

